# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

public async Task<bool> PurchaseTicketsAsync(int eventId, int requestedQuantity)
{
    using (var dbContext = new EventBookingContext())
    {
        using (var transaction = await dbContext.Database.BeginTransactionAsync())
        {
            var eventDetails = await dbContext.Events
                .Where(e => e.Id == eventId)
                .Include(e => e.Seats)
                .FirstOrDefaultAsync();

            if (eventDetails == null || eventDetails.AvailableSeats < requestedQuantity)
            {
                return false; // Not enough available seats
            }

            eventDetails.AvailableSeats -= requestedQuantity;

            dbContext.Events.Update(eventDetails);
            
            await dbContext.SaveChangesAsync();
            await transaction.CommitAsync();
        }
    }

    return true; // Purchase successful
}